[Console]::OutputEncoding = [Text.Encoding]::UTF8
$folder = (Get-ChildItem 'E:\Data\Users\cherkasov.n\Desktop' -Directory | Where-Object { $_.Name -like '*папка*' -or $_.Name -eq 'Новая папка' } | Select-Object -First 1).FullName
if (-not $folder) { $folder = 'E:\Data\Users\cherkasov.n\Desktop\Новая папка' }
Write-Output "FOLDER=$folder"
Get-ChildItem -LiteralPath $folder | ForEach-Object { $_.Name }

# Extract docx text via Word COM or Expand-Archive
$outDir = 'C:\Users\cherkasov.n\openAIKey\_infra_extract'
New-Item $outDir -ItemType Directory -Force | Out-Null

Add-Type -AssemblyName System.IO.Compression.FileSystem
Get-ChildItem -LiteralPath $folder -Filter *.docx | ForEach-Object {
  $name = $_.BaseName
  $tmp = Join-Path $env:TEMP ("docx_" + [guid]::NewGuid().ToString())
  New-Item $tmp -ItemType Directory | Out-Null
  try {
    [IO.Compression.ZipFile]::ExtractToDirectory($_.FullName, $tmp)
    $xml = Get-Content (Join-Path $tmp 'word\document.xml') -Raw -Encoding UTF8
    $text = [regex]::Replace($xml, '</w:p>', "`n")
    $text = [regex]::Replace($text, '<[^>]+>', '')
    $text = [System.Net.WebUtility]::HtmlDecode($text)
    $out = Join-Path $outDir ($name + '.txt')
    Set-Content -LiteralPath $out -Value $text -Encoding UTF8
    Write-Output "EXTRACTED: $out ($((Get-Item $out).Length) bytes)"
  } catch {
    Write-Output "FAIL $($_.Name): $_"
  } finally {
    Remove-Item $tmp -Recurse -Force -ErrorAction SilentlyContinue
  }
}

[Console]::OutputEncoding = [Text.Encoding]::UTF8
# Update home ovpn: explicit gateway 10.220.220.254 instead of vpn_gateway
$files = @(
  'C:\Users\cherkasov.n\Desktop\port-mol-home.ovpn',
  'E:\Data\Users\cherkasov.n\Desktop\port-mol-home.ovpn',
  'E:\Data\Users\cherkasov.n\Desktop\port-mol.ovpn'
)
foreach ($f in $files) {
  if (-not (Test-Path -LiteralPath $f)) { continue }
  $t = [IO.File]::ReadAllText($f)
  $n = $t.Replace(
    "route 192.168.2.0 255.255.255.0 vpn_gateway`r`nroute 192.168.10.0 255.255.255.0 vpn_gateway`r`nroute 192.168.20.0 255.255.255.0 vpn_gateway",
    "route-nopull`r`nroute 192.168.2.0 255.255.255.0 10.220.220.254`r`nroute 192.168.10.0 255.255.255.0 10.220.220.254`r`nroute 192.168.20.0 255.255.255.0 10.220.220.254"
  )
  if ($n -eq $t) {
    $n = $t.Replace(
      "route 192.168.2.0 255.255.255.0 vpn_gateway`nroute 192.168.10.0 255.255.255.0 vpn_gateway`nroute 192.168.20.0 255.255.255.0 vpn_gateway",
      "route-nopull`nroute 192.168.2.0 255.255.255.0 10.220.220.254`nroute 192.168.10.0 255.255.255.0 10.220.220.254`nroute 192.168.20.0 255.255.255.0 10.220.220.254"
    )
  }
  # keep pull for IP/DNS but we already have pull-filter for redirect-gateway
  # route-nopull disables ALL pull including IP - BAD. Don't use route-nopull.
  $n = $n.Replace("route-nopull`r`n", "").Replace("route-nopull`n", "")
  [IO.File]::WriteAllText($f, $n)
  Write-Output "updated $f"
  Select-String -LiteralPath $f -Pattern '^route |^pull' | ForEach-Object { $_.Line }
}

